import{_ as t,o as a,c as o,ae as n}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Add & Manage Users","description":"","frontmatter":{"title":"Add & Manage Users","slug":"add-manage-users"},"headers":[],"relativePath":"account-hub/add-manage-users.md","filePath":"account-hub/add-manage-users.md"}'),r={name:"account-hub/add-manage-users.md"};function i(s,e,l,c,d,h){return a(),o("div",null,[...e[0]||(e[0]=[n('<div class="danger custom-block"><p class="custom-block-title">Warning</p><p>This article outlines the legacy Team tab, which is part of the <a href="./branch-dashboard-overview.html">legacy Branch</a> experience and is slated for deprecation.</p><p>In the <a href="./new-branch-overview.html">new</a> Branch platform, you can find team information by navigating to <strong>Configuration → Security &amp; Access →</strong> <a href="https://branchdocs.app.link/security-access-team" target="_blank" rel="noreferrer"><strong>Team</strong></a>. See more information about the new Team tab in our <a href="./team.html">guide</a>.</p></div><h2 id="add-users-to-branch-dashboard" tabindex="-1">Add Users to Branch Dashboard <a class="header-anchor" href="#add-users-to-branch-dashboard" aria-label="Permalink to &quot;Add Users to Branch Dashboard&quot;">​</a></h2><ol><li><p>In the Branch Dashboard, go to the <a href="https://branch.dashboard.branch.io/account-settings/profile" target="_blank" rel="noreferrer">Settings</a> page under the Account section of the navigation bar, and click to the <a href="https://dashboard.branch.io/account-settings/team" target="_blank" rel="noreferrer">Team</a> tab.</p></li><li><p>Click <strong>Add App Team Member</strong>.</p></li><li><p>Enter the email address of the user you wish to add.</p></li><li><p>Click <strong>Search User</strong>.</p></li><li><p>If the user does not already exist, you will be prompted to complete the following fields:<br> a. First Name<br> b. Last Name<br> c. <a href="./entity-views-access-controls-overview.html#access-levels">Access Level</a>, your options are:</p><ol><li><strong>Admin</strong></li><li><strong>Team Member</strong></li><li><strong>Full Read</strong></li><li><strong>Limited Read</strong></li><li><strong>User Coordinator</strong></li><li><strong>Custom</strong> - If you choose Custom, you will have to define each access level you wish to grant that user. Your options are:<br> a. <strong>Link-level Settings</strong> - Settings or features that can impact functionality for single links.<br> b. <strong>Channel-level Settings</strong> - Settings or features that can impact functionality across a marketing channel.<br> c. <strong>App-level Settings</strong> - Settings or features that can impact functionality app-wide.<br> d. <strong>Aggregate Data</strong> - Summary data that contains no granular data.<br> e. <strong>Sensitive Data</strong> - Data that can contain user-identifying, payment-related, or secret information.<br> f. <strong>Fraud Settings &amp; Data</strong> - Settings or data associated with fraud detection and prevention.</li></ol></li><li><p>Click <strong>Invite</strong> when you&#39;re done.<br> a. If you are adding a user to your <a href="./entity-views-access-controls-overview.html#organization-view">Organization View</a>, select one of the follow and click <strong>Save</strong>:</p><ul><li>All apps that inherit from the organization</li><li>All apps</li></ul></li></ol><h2 id="manage-users" tabindex="-1">Manage Users <a class="header-anchor" href="#manage-users" aria-label="Permalink to &quot;Manage Users&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">Note</p><p>Branch team members are not authorized to complete the following actions on your behalf. Your admin users must complete user management tasks.</p></div><h3 id="modifying-existing-team-member" tabindex="-1">Modifying Existing Team Member <a class="header-anchor" href="#modifying-existing-team-member" aria-label="Permalink to &quot;Modifying Existing Team Member&quot;">​</a></h3><p>To modify an existing team member:</p><ol><li>Find the team member you want to modify and click the <code>...</code> button in the Actions column for that user.</li><li>To edit the Organization Team member, select <strong>Edit.</strong></li><li>Click <strong>Save</strong>.</li></ol><div class="danger custom-block"><p class="custom-block-title">Warning</p><p>If you are using the <a href="./branch-dashboard-overview.html">legacy version of Branch</a> and need to change the email address associated with your account, please contact <a href="https://support.branch.io/hc/en-us/requests/new" target="_blank" rel="noreferrer">Support</a>.</p><p>To learn about the new Branch experience and the features rolling out in 2026, visit our <a href="./new-branch-overview.html">New Branch Overview</a> guide.</p></div><h3 id="resend-invitation-to-join" tabindex="-1">Resend Invitation to Join <a class="header-anchor" href="#resend-invitation-to-join" aria-label="Permalink to &quot;Resend Invitation to Join&quot;">​</a></h3><p>To resend the invitation to join the account:</p><ol><li>Find the Organization Team member you want to modify and click the <code>...</code> button in the <strong>Actions</strong> column for that user.</li><li>Click <strong>Resend Invite</strong>.</li></ol><h3 id="delete-team-member" tabindex="-1">Delete Team Member <a class="header-anchor" href="#delete-team-member" aria-label="Permalink to &quot;Delete Team Member&quot;">​</a></h3><ol><li>Find the team member you want to delete and click the <code>...</code> button in the <strong>Actions</strong> column for that user.</li><li>Click <strong>Delete</strong>.</li><li>In the <strong>Are you sure you want to delete?</strong> modal, click <strong>Yes, Delete</strong>.</li></ol><h3 id="request-additional-permissions" tabindex="-1">Request Additional Permissions <a class="header-anchor" href="#request-additional-permissions" aria-label="Permalink to &quot;Request Additional Permissions&quot;">​</a></h3><p>As a non-Admin user, you may not be able to access/use certain sections of the Branch dashboard. If you’d like more access, please contact an Admin user on your account to ask for more permissions.</p><p>If you need further assistance, feel free to reach out to <a href="mailto:integrations@branch.io" target="_blank" rel="noreferrer">integrations@branch.io</a>.</p>',17)])])}const g=t(r,[["render",i]]);export{u as __pageData,g as default};
